  1	import * as React from 'react';
  2	import {
  3	  Alert,
  4	  AlertActionCloseButton,
  5	  AlertVariant,
  6	  Card,
  7	  CardBody,
  8	  Tab,
  9	  Tabs,
 10	  Toolbar,
 11	  ToolbarGroup,
 12	  ToolbarItem,
 13	  Tooltip
 14	} from '@patternfly/react-core';
 15	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
 16	import { connect } from 'react-redux';
 17	import * as API from 'services/Api';
 18	import * as AlertUtils from 'utils/AlertUtils';
 19	import { RenderComponentScroll } from '../Nav/Page';
 20	import { KioskElement } from '../Kiosk/KioskElement';
 21	import { TimeDurationModal } from '../Time/TimeDurationModal';
 22	import { KialiAppState } from 'store/Store';
 23	import { JaegerTrace, TracingError } from 'types/TracingInfo';
 24	import { TraceDetails } from './TracingResults/TraceDetails';
 25	import { TracingScatter } from './TracingScatter';
 26	import { FetchOptions, TracesFetcher } from './TracesFetcher';
 27	import { SpanDetails } from './TracingResults/SpanDetails';
 28	import {
 29	  durationToBounds,
 30	  guardTimeRange,
 31	  isEqualTimeRange,
 32	  TargetKind,
 33	  TimeInMilliseconds,
 34	  TimeRange
 35	} from 'types/Common';
 36	import { timeRangeSelector } from 'store/Selectors';
 37	import { DisplaySettings, percentilesOptions, QuerySettings, TracesDisplayOptions } from './TracesDisplayOptions';
 38	import { Direction, genStatsKey, MetricsStatsQuery } from 'types/MetricsOptions';
 39	import { MetricsStatsResult } from 'types/Metrics';
 40	import { getSpanId } from 'utils/SearchParamUtils';
 41	import { TimeDurationIndicator } from '../Time/TimeDurationIndicator';
 42	import { subTabStyle } from 'styles/TabStyles';
 43	import { JAEGER, TracingUrlProvider } from 'types/Tracing';
 44	import { GetTracingUrlProvider } from 'utils/tracing/UrlProviders';
 45	import { ExternalServiceInfo } from 'types/StatusState';
 46	import { retrieveTimeRange } from '../Time/TimeRangeHelper';
 47	import { isParentKiosk, kioskTracingAction } from '../Kiosk/KioskActions';
 48	
 49	type ReduxProps = {
 50	  externalServices: ExternalServiceInfo[];
 51	  kiosk: string;
 52	  namespaceSelector: boolean;
 53	  provider?: string;
 54	  selectedTrace?: JaegerTrace;
 55	  timeRange: TimeRange;
 56	  urlTracing: string;
 57	};
 58	
 59	type TracesProps = ReduxProps & {
 60	  cluster?: string;
 61	  fromWaypoint: boolean;
 62	  lastRefreshAt: TimeInMilliseconds;
 63	  namespace: string;
 64	  target: string;
 65	  targetKind: TargetKind;
 66	  waypointServiceFilter?: string;
 67	};
 68	
 69	interface TracesState {
 70	  activeTab: number;
 71	  displaySettings: DisplaySettings;
 72	  infoMessage?: string;
 73	  isTimeOptionsOpen: boolean;
 74	  querySettings: QuerySettings;
 75	  targetApp?: string;
 76	  toolbarDisabled: boolean;
 77	  traces: JaegerTrace[];
 78	  tracingErrors: TracingError[];
 79	  url: string;
 80	  visibleAlert: boolean;
 81	  width: number;
 82	}
 83	
 84	const traceDetailsTab = 0;
 85	const spansDetailsTab = 1;
 86	
 87	class TracesComp extends React.Component<TracesProps, TracesState> {
 88	  private fetcher: TracesFetcher;
 89	  private urlProvider: TracingUrlProvider | undefined;
 90	  private percentilesPromise: Promise<Map<string, number>>;
 91	
 92	  constructor(props: TracesProps) {
 93	    super(props);
 94	    let targetApp: string | undefined = undefined;
 95	    if (this.props.targetKind === 'app') {
 96	      targetApp = this.props.namespaceSelector ? `${this.props.target}.${this.props.namespace}` : this.props.target;
 97	    }
 98	    this.state = {
 99	      isTimeOptionsOpen: false,
100	      url: '',
101	      width: 0,
102	      querySettings: TracesDisplayOptions.retrieveQuerySettings(),
103	      displaySettings: TracesDisplayOptions.retrieveDisplaySettings(),
104	      traces: [],
105	      tracingErrors: [],
106	      targetApp: targetApp,
107	      activeTab: getSpanId() ? spansDetailsTab : traceDetailsTab,
108	      toolbarDisabled: false,
109	      visibleAlert: true
110	    };
111	    this.fetcher = new TracesFetcher(
112	      this.onTracesUpdated,
113	      errors => {
114	        // If there were already traces displayed, do not hide them so that the user can still interact with them
115	        // (consider it's probably a temporary failure)
116	        // Note that the error message is anyway displayed in the notifications component, so it's not going unnoticed
117	        if (this.state.traces.length === 0) {
118	          this.setState({ tracingErrors: errors, toolbarDisabled: true });
119	        }
120	      },
121	      info => {
122	        this.setState({ infoMessage: info, visibleAlert: true });
123	      }
124	    );
125	    // This establishes the percentile-based filtering levels
126	    this.percentilesPromise = this.fetchPercentiles();
127	
128	    this.urlProvider = this.getUrlProvider();
129	  }
130	
131	  componentDidMount(): void {
132	    this.fetchTraces();
133	  }
134	
135	  componentDidUpdate(prevProps: TracesProps): void {
136	    // Selected trace (coming from redux) might have been reloaded and needs to be updated within the traces list
137	    // Check reference of selected trace
138	    if (this.props.selectedTrace && prevProps.selectedTrace !== this.props.selectedTrace) {
139	      const traces = this.state.traces;
140	      const trace = this.props.selectedTrace;
141	      const index = traces.findIndex(t => t.traceID === trace.traceID);
142	      if (index >= 0) {
143	        traces[index] = this.props.selectedTrace;
144	        this.setState({ traces: traces });
145	      }
146	    }
147	
148	    const changedTimeRange = !isEqualTimeRange(this.props.timeRange, prevProps.timeRange);
149	    if (this.props.lastRefreshAt !== prevProps.lastRefreshAt || changedTimeRange) {
150	      if (changedTimeRange) {
151	        this.fetcher.resetLastFetchTime();
152	      }
153	      this.fetchTraces();
154	    }
155	  }
156	
157	  private getTags = (): Record<string, string> => {
158	    return this.state.querySettings.errorsOnly ? { error: 'true' } : {};
159	  };
160	
161	  private fetchTraces = async (): Promise<void> => {
162	    const options: FetchOptions = {
163	      namespace: this.props.namespace,
164	      cluster: this.props.cluster,
165	      target: this.props.target,
166	      targetKind: this.props.targetKind,
167	      spanLimit: this.state.querySettings.limit,
168	      tags: JSON.stringify(this.getTags())
169	    };
170	    // If percentil filter is set fetch only traces above the specified percentile
171	    // Percentiles (99th, 90th, 75th) are pre-computed from metrics bound to this app/workload/service object.
172	    if (this.state.querySettings.percentile && this.state.querySettings.percentile !== 'all') {
173	      try {
174	        const percentiles = await this.percentilesPromise;
175	        options.minDuration = percentiles.get(this.state.querySettings.percentile);
176	        if (!options.minDuration) {
177	          AlertUtils.addWarning('Cannot perform query above the requested percentile (value unknown).');
178	        }
179	      } catch (err) {
180	        AlertUtils.addError(`Could not fetch percentiles: ${err}`);
181	      }
182	    }
183	    this.fetcher.fetch(options, this.state.traces);
184	  };
185	
186	  private fetchPercentiles = (): Promise<Map<string, number>> => {
187	    // We'll fetch percentiles on a large enough interval (unrelated to the selected interval)
188	    // in order to have stable values and avoid constantly fetching again
189	    const query: MetricsStatsQuery = {
190	      queryTime: Math.floor(Date.now() / 1000),
191	      target: {
192	        namespace: this.props.namespace,
193	        name: this.props.target,
194	        kind: this.props.targetKind,
195	        cluster: this.props.cluster
196	      },
197	      interval: '1h',
198	      direction: 'inbound',
199	      avg: false,
200	      quantiles: percentilesOptions.map(p => p.id).filter(id => id !== 'all')
201	    };
202	    const queries: MetricsStatsQuery[] =
203	      this.props.targetKind === 'service' ? [query] : [query, { ...query, direction: 'outbound' }];
204	    return API.getMetricsStats(queries).then(r => this.percentilesFetched(query, r.data));
205	  };
206	
207	  private percentilesFetched = (q: MetricsStatsQuery, r: MetricsStatsResult): Map<string, number> => {
208	    if (r.warnings) {
209	      AlertUtils.addWarning(r.warnings.join(', '));
210	    }
211	    const [mapInbound, mapOutbound] = (['inbound', 'outbound'] as Direction[]).map(dir => {
212	      const map = new Map<string, number>();
213	      const key = genStatsKey(q.target, undefined, dir, q.interval);
214	      if (key) {
215	        const statsForKey = r.stats[key];
216	        if (statsForKey) {
217	          statsForKey.responseTimes.forEach(rt => {
218	            if (q.quantiles.includes(rt.name)) {
219	              map.set(rt.name, rt.value);
220	            }
221	          });
222	        }
223	      }
224	      return map;
225	    });
226	    // Merge the two maps; if a value exists in both of them, take the mean
227	    const minDurations = new Map<string, number>();
228	    mapInbound.forEach((v1, k) => {
229	      const v2 = mapOutbound.get(k);
230	      if (v2) {
231	        minDurations.set(k, (v1 + v2) / 2);
232	        mapOutbound.delete(k);
233	      } else {
234	        minDurations.set(k, v1);
235	      }
236	    });
237	    mapOutbound.forEach((v, k) => minDurations.set(k, v));
238	    return minDurations;
239	  };
240	
241	  private onTracesUpdated = (traces: JaegerTrace[], tracingServiceName: string): void => {
242	    const newState: Partial<TracesState> = { traces: traces, tracingErrors: undefined, toolbarDisabled: false };
243	    if (this.state.targetApp === undefined && tracingServiceName) {
244	      newState.targetApp = tracingServiceName;
245	    }
246	    this.setState(newState as TracesState);
247	  };
248	
249	  private getUrlProvider = (): TracingUrlProvider | undefined =>
250	    GetTracingUrlProvider(this.props.externalServices, this.props.provider);
251	
252	  private getTracingUrl = (): string | undefined => {
253	    if (!this.urlProvider || !this.state.targetApp || !this.urlProvider.HomeUrl()) {
254	      return undefined;
255	    }
256	    const range = retrieveTimeRange();
257	    // Convert any time range (like duration) to bounded from/to
258	    const boundsMillis = guardTimeRange(range, durationToBounds, b => b);
259	    return this.urlProvider.AppSearchUrl(
260	      this.state.targetApp,
261	      boundsMillis,
262	      this.getTags(),
263	      this.state.querySettings.limit
264	    );
265	  };
266	
267	  private onQuerySettingsChanged = (settings: QuerySettings): void => {
268	    this.fetcher.resetLastFetchTime();
269	    this.setState({ querySettings: settings }, this.fetchTraces);
270	  };
271	
272	  private onDisplaySettingsChanged = (settings: DisplaySettings): void => {
273	    this.setState({ displaySettings: settings });
274	  };
275	
276	  private toggleTimeOptionsVisibility = (): void => {
277	    this.setState(prevState => ({ isTimeOptionsOpen: !prevState.isTimeOptionsOpen }));
278	  };
279	
280	  render(): JSX.Element {
281	    const tracingURL = this.getTracingUrl();
282	    return (
283	      <>
284	        <RenderComponentScroll>
285	          <Card>
286	            <CardBody>
287	              <Toolbar style={{ padding: 0 }}>
288	                {this.state.infoMessage && this.state.visibleAlert && (
289	                  <ToolbarGroup>
290	                    <ToolbarItem style={{ width: '100%' }}>
291	                      <Alert
292	                        style={{ width: '100%' }}
293	                        isInline={true}
294	                        variant={AlertVariant.info}
295	                        title={this.state.infoMessage}
296	                        actionClose={<AlertActionCloseButton onClose={() => this.setState({ visibleAlert: false })} />}
297	                      />
298	                    </ToolbarItem>
299	                  </ToolbarGroup>
300	                )}
301	                <ToolbarGroup>
302	                  <ToolbarItem>
303	                    <TracesDisplayOptions
304	                      onDisplaySettingsChanged={this.onDisplaySettingsChanged}
305	                      onQuerySettingsChanged={this.onQuerySettingsChanged}
306	                      percentilesPromise={this.percentilesPromise}
307	                      disabled={this.state.toolbarDisabled}
308	                    />
309	                  </ToolbarItem>
310	                  <ToolbarItem style={{ marginLeft: 'auto' }}>
311	                    {/*Blank item used as a separator do shift the following ToolbarItems to the right*/}
312	                  </ToolbarItem>
313	                  {(tracingURL || isParentKiosk(this.props.kiosk)) && (
314	                    <ToolbarItem>
315	                      <Tooltip
316	                        content={<>Open Chart in {this.props.provider === JAEGER ? this.props.provider : 'the'} UI</>}
317	                      >
318	                        <a
319	                          href={tracingURL}
320	                          target="_blank"
321	                          rel="noopener noreferrer"
322	                          style={{ marginLeft: '10px' }}
323	                          data-test="view-in-tracing"
324	                          onClick={e => {
325	                            if (isParentKiosk(this.props.kiosk)) {
326	                              e.preventDefault();
327	                              kioskTracingAction(tracingURL);
328	                            } else {
329	                              window.open(tracingURL, '_blank');
330	                            }
331	                          }}
332	                        >
333	                          View in Tracing <ExternalLinkAltIcon />
334	                        </a>
335	                      </Tooltip>
336	                    </ToolbarItem>
337	                  )}
338	                  <KioskElement>
339	                    <ToolbarItem>
340	                      <TimeDurationIndicator onClick={this.toggleTimeOptionsVisibility} />
341	                    </ToolbarItem>
342	                  </KioskElement>
343	                </ToolbarGroup>
344	              </Toolbar>
345	              <TracingScatter
346	                showSpansAverage={this.state.displaySettings.showSpansAverage}
347	                traces={this.state.traces}
348	                errorFetchTraces={this.state.tracingErrors}
349	                errorTraces={true}
350	                cluster={this.props.cluster ? this.props.cluster : ''} // TODO: Test single cluster
351	              />
352	            </CardBody>
353	          </Card>
354	          {this.props.selectedTrace && (
355	            <div
356	              style={{
357	                marginTop: 25
358	              }}
359	            >
360	              <Tabs
361	                id="trace-details"
362	                data-test="trace-details-tabs"
363	                className={subTabStyle}
364	                activeKey={this.state.activeTab}
365	                onSelect={(_, idx: any) => this.setState({ activeTab: idx })}
366	              >
367	                <Tab eventKey={traceDetailsTab} title="Trace Details">
368	                  <TraceDetails
369	                    namespace={this.props.namespace}
370	                    target={this.props.target}
371	                    targetKind={this.props.targetKind}
372	                    tracingURLProvider={this.urlProvider}
373	                    otherTraces={this.state.traces}
374	                    cluster={this.props.cluster ? this.props.cluster : ''}
375	                    provider={this.props.provider}
376	                  />
377	                </Tab>
378	                <Tab eventKey={spansDetailsTab} title="Span Details">
379	                  <SpanDetails
380	                    namespace={this.props.namespace}
381	                    target={this.props.target}
382	                    externalURLProvider={this.urlProvider}
383	                    items={this.props.selectedTrace.spans}
384	                    traceID={this.props.selectedTrace.traceID}
385	                    cluster={this.props.cluster ? this.props.cluster : ''}
386	                    fromWaypoint={this.props.fromWaypoint}
387	                    waypointServiceFilter={this.props.waypointServiceFilter}
388	                  />
389	                </Tab>
390	              </Tabs>
391	            </div>
392	          )}
393	        </RenderComponentScroll>
394	        <TimeDurationModal
395	          customDuration={true}
396	          isOpen={this.state.isTimeOptionsOpen}
397	          onConfirm={this.toggleTimeOptionsVisibility}
398	          onCancel={this.toggleTimeOptionsVisibility}
399	        />
400	      </>
401	    );
402	  }
403	}
404	
405	const mapStateToProps = (state: KialiAppState): ReduxProps => {
406	  return {
407	    externalServices: state.statusState.externalServices,
408	    kiosk: state.globalState.kiosk,
409	    namespaceSelector: state.tracingState.info ? state.tracingState.info.namespaceSelector : true,
410	    provider: state.tracingState.info?.provider,
411	    selectedTrace: state.tracingState.selectedTrace,
412	    timeRange: timeRangeSelector(state),
413	    urlTracing: state.tracingState.info ? state.tracingState.info.url : ''
414	  };
415	};
416	
417	export const TracesComponent = connect(mapStateToProps)(TracesComp);

