202	    const queries: MetricsStatsQuery[] =
203	      this.props.targetKind === 'service' ? [query] : [query, { ...query, direction: 'outbound' }];
204	    return API.getMetricsStats(queries).then(r => this.percentilesFetched(query, r.data));
205	  };
